var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set (metrics are approximate with small datasets)
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine("=== Churn Model Metrics ===");
Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");

mlContext.Model.Save(model, labeledData.Schema, modelPath);

arguments.new_str:
var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set (metrics may be unreliable with very small datasets)
try
{
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine("=== Churn Model Metrics ===");
    Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
    Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("=== Churn Model Metrics ===");
    Console.WriteLine("Test set too small for reliable metrics. Add more data for proper evaluation.");
}

mlContext.Model.Save(model, labeledData.Schema, modelPath);

